onOptionChange:
{{
  (async () => {
    const operacionId = sl_operacion.selectedOptionValue || "";
    const operacionLabel = sl_operacion.selectedOptionLabel || "";

    if (!operacionId) {
      await storeValue("booking_form", {
        ...appsmith.store.booking_form,
        tipo_operacion_exportacion_id: "",
        tipo_operacion_exportacion_label: "",
        operacion_no: ""
      });

      await storeValue("current_operacion_tipo_id", "");
      await storeValue("current_operacion_no", "");
      return;
    }

    await storeValue("booking_form", {
      ...appsmith.store.booking_form,
      tipo_operacion_exportacion_id: operacionId,
      tipo_operacion_exportacion_label: operacionLabel
    });

    await storeValue("current_operacion_tipo_id", operacionId);

    const preview = await q_operacion_no_preview.run();
    const operacionNo = preview?.[0]?.preview_operacion_no || "";

    await storeValue("booking_form", {
      ...appsmith.store.booking_form,
      tipo_operacion_exportacion_id: operacionId,
      tipo_operacion_exportacion_label: operacionLabel,
      operacion_no: operacionNo
    });

    await storeValue("current_operacion_no", operacionNo);

    showAlert("Consecutivo actualizado: " + operacionNo, "success");
  })()
}}
